import os
from docx import Document
from docx.shared import Pt
from docx.enum.text import WD_ALIGN_PARAGRAPH

def apply_style(run, bold=False, italic=False, size=13):
    run.font.name = 'Times New Roman'
    run.font.size = Pt(size)
    run.bold = bold
    run.italic = italic

def add_heading(doc, text, level):
    p = doc.add_paragraph()
    p.paragraph_format.space_after = Pt(6)
    p.paragraph_format.space_before = Pt(6)
    run = p.add_run(text)
    if level == 0: # Chapter Title
        p.alignment = WD_ALIGN_PARAGRAPH.CENTER
        apply_style(run, bold=True, size=15)
    elif level == 1: # 3.1
        apply_style(run, bold=True, size=13)
    elif level == 2: # 3.1.1
        apply_style(run, bold=True, size=13)
    elif level == 3: # 3.1.1.1
        apply_style(run, bold=True, italic=True, size=13)

def add_paragraph(doc, text, italic=False, bold=False):
    p = doc.add_paragraph()
    p.paragraph_format.first_line_indent = Pt(36) # ~1.27cm
    p.paragraph_format.space_after = Pt(6)
    p.paragraph_format.line_spacing = 1.3
    p.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    run = p.add_run(text)
    apply_style(run, size=13, italic=italic, bold=bold)

def add_bullet(doc, text):
    p = doc.add_paragraph(style='List Bullet')
    p.paragraph_format.space_after = Pt(6)
    p.paragraph_format.line_spacing = 1.3
    p.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    run = p.add_run(text)
    apply_style(run, size=13)

