    add_heading(doc, "3.7.7 Trình phát bài giảng tương tác (Interactive Lesson Player)", 2)
    add_paragraph(doc, "Đây là tính năng cốt lõi, thay thế các công cụ trình chiếu truyền thống bằng một môi trường thực thi bài giảng trực tiếp trên trình duyệt.")
